def _generate_nav_file(self, docs: List[Document]):
        """Generate navigation file (_sidebar.md or README)"""
        # Group by type
        groups = {}
        for doc in docs:
            groups.setdefault(doc.doc_type.value, []).append(doc)

        lines = ["# 文档导航\n"]

        # Overview and architecture first
        for doc_type in ['overview', 'architecture', 'module', 'api']:
            if doc_type in groups:
                type_name = {
                    'overview': '项目概览',
                    'architecture': '架构设计',
                    'module': '模块文档',
                    'api': 'API 文档'
                }.get(doc_type, doc_type)

                lines.append(f"## {type_name}")
                for doc in sorted(groups[doc_type], key=lambda d: d.file_path):
                    lines.append(f"- [{doc.title}]({doc.file_path})")
                lines.append("")

        nav_content = "\n".join(lines)
        (self.wiki_path / "_sidebar.md").write_text(nav_content, encoding='utf-8')

        # Also update homepage README
        readme_content = self._generate_readme(docs)
        (self.wiki_path / "README.md").write_text(readme_content, encoding='utf-8')

def clean(self):
        """Clean all generated documents"""
        import shutil
        if self.wiki_path.exists():
            shutil.rmtree(self.wiki_path)
            self.wiki_path.mkdir(parents=True, exist_ok=True)

def _init_client(self) -> openai.OpenAI:
        """Initialize OpenAI client based on provider"""
        provider_config = self.PROVIDER_CONFIGS[self.provider]

        # Get API Key
        api_key = self.config.get('api_key')
        if provider_config['requires_api_key'] and not api_key:
            raise ValueError(f"{self.provider.value} requires api_key")

        # For providers that don't require API key (like Ollama), set a dummy value
        if not api_key:
            api_key = "dummy_key"  # OpenAI client requires this parameter

        # Get base_url
        base_url = self.config.get('base_url', provider_config['default_base_url'])

        return openai.OpenAI(
            api_key=api_key,
            base_url=base_url
        )

def generate_stream(self, prompt: str) -> Generator[str, None, None]:
        """Stream generation (for chat command)"""
        if self.mock:
            # Mock mode - return simulated streaming response
            logger.debug(f"Stream generation in MOCK mode: {prompt[:100]}...")

            mock_response = f"This is a mock streaming response generated in MOCK mode.\n\nThe LLM would normally analyze your request and generate a detailed response, but in mock mode, we're returning this simulated output.\n\nRequest: {prompt[:200]}...\n\n[MOCK STREAMING RESPONSE END]"

            # Simulate streaming by yielding chunks
            chunks = mock_response.split(' ')
            for i, chunk in enumerate(chunks):
                yield chunk + (' ' if i < len(chunks) - 1 else '')

            return

        try:
            stream = self.client.chat.completions.create(
                model=self.model,
                messages=[{"role": "user", "content": prompt}],
                stream=True,
                max_tokens=self.max_tokens
            )

            for chunk in stream:
                if chunk.choices[0].delta.content:
                    yield chunk.choices[0].delta.content

        except Exception as e:
            logger.error(f"Stream generation failed: {e}")
            raise

def _clean_markdown(self, content: str) -> str:
        """Clean LLM output markdown format"""
        lines = content.split('\n')
        if lines and lines[0].strip().startswith('```'):
            lines = lines[1:]
        if lines and lines[-1].strip() == '```':
            lines = lines[:-1]
        return '\n'.join(lines).strip()

from typing import List, Optional, Dict, Any
import os
from openai import OpenAI
from codemind.generator.base import DocumentationGenerator
from codemind.parser.models.symbol import Symbol, FunctionSymbol, ClassSymbol
from codemind.parser.models.chunk import CodeChunk
from codemind.config.schemas import LLMConfig, LLMProvider
from codemind.core.logger import logger


class LLMGenerator(DocumentationGenerator):
    """基于LLM的文档生成器"""

    def __init__(self, config: LLMConfig):
        """初始化LLM生成器

        Args:
            config: LLM配置
        """
        self.config = config
        self.client = self._create_client()

    def _create_client(self) -> OpenAI:
        """创建OpenAI客户端

        Returns:
            OpenAI客户端实例
        """
        if self.config.provider == LLMProvider.OLLAMA:
            return OpenAI(
                base_url=self.config.base_url,
                api_key="ollama"  # Ollama不需要真实API密钥
            )
        elif self.config.provider == LLMProvider.DEEPSEEK:
